package com.interview.incidentrca.service;
import com.interview.incidentrca.entity.Incident;import com.interview.incidentrca.enums.*;import org.springframework.stereotype.Service;import java.time.*;import java.util.Map;
@Service public class SlaService{private static final Map<Severity,Duration> SLA=Map.of(Severity.CRITICAL,Duration.ofHours(1),Severity.HIGH,Duration.ofHours(4),Severity.MEDIUM,Duration.ofHours(12),Severity.LOW,Duration.ofHours(24)); public SlaState state(Incident i){if(i.getResolvedAt()!=null)return Duration.between(i.getCreatedAt(),i.getResolvedAt()).compareTo(SLA.get(i.getSeverity()))>0?SlaState.BREACHED:SlaState.WITHIN_SLA;Duration used=Duration.between(i.getCreatedAt(),Instant.now());Duration limit=SLA.get(i.getSeverity());if(used.compareTo(limit)>0)return SlaState.BREACHED;if(used.toMillis()>=limit.toMillis()*0.8)return SlaState.NEAR_BREACH;return SlaState.WITHIN_SLA;} public Instant breachCutoff(Severity s){return Instant.now().minus(SLA.get(s));}}
